#include<bits/stdc++.h>
using namespace std;
int n,k,m,v[50010],r[50010];
struct st
{
    int a[50010],lg[50010];
    int f[50010][21];
    void init()
    {
        lg[1]=0;
        for(int i=2;i<=n;i++)
        {
            lg[i]=lg[i/2]+1;
        }
        for(int i=1;i<=n;i++)
        {
            f[i][0]=a[i];
        }
        for(int j=1;j<=lg[n];j++)
        {
            for(int i=1;(i+(1<<j)-1)<=n;i++)
            {
                f[i][j]=max(f[i][j-1],f[i+(1<<(j-1))][j-1]);
            }
        }
    }
    int getmax(int l,int r)
    {
        if(l>r)
        {
            return -2e9;
        }
        int tmp=lg[r-l+1];
        return max(f[l][tmp],f[r-(1<<tmp)+1][tmp]);
    }
}t;
int main()
{
    scanf("%d",&n);
    k=n;
    for(int i=1;i<=n;i++)
    {
        scanf("%d%d",&v[i],&r[i]);
        t.a[i]=r[i];
    }
    t.init();
    int m;
    scanf("%d",&m);
    while(m--)
    {
        int x,y;
        scanf("%d%d",&x,&y);
        int tmp=lower_bound(v+1,v+1+n,x)-v;
        int tmp1=lower_bound(v+1,v+1+n,y)-v;
        if(v[tmp]!=x&&tmp<=n&&tmp1<=n&&v[tmp1]==y&&t.getmax(tmp,tmp1-1)>=r[tmp1])
        {
            printf("false\n");
            continue;
        }
        if(tmp<=n&&v[tmp]==x&&(tmp1>n||v[tmp1]!=y)&&t.getmax(tmp+1,tmp1-1)>=r[tmp])
        {
            printf("false\n");
            continue;
        }
        if(tmp>n||tmp1>n||v[tmp]!=x||v[tmp1]!=y)
        {
            printf("maybe\n");
            continue;
        }
        if(r[tmp1]>r[tmp])
        {
            printf("false\n");
            continue;
        }
        if(t.getmax(tmp+1,tmp1-1)>=r[tmp1])
        {
            printf("false\n");
            continue;
        }
        if(tmp1-tmp!=v[tmp1]-v[tmp])
        {
            printf("maybe\n");
            continue;
        }
        printf("true\n");
    }
    return 0;
}
